template<const int N>
class Matrixmn {
public:
	array<array<ll, N + 1>, N + 1> mat;

	Matrixmn() {
		for (int i = 0; i <= N; i++)
			for (int j = 0; j <= N; j++)
				mat[i][j] = 1e16;
	}

	Matrixmn operator* (const Matrixmn& x) {
		// floyd 求最短路
		Matrixmn ret;
		for (int k = 1; k <= N; k++)
			for (int i = 1; i <= N; i++) {
				if (mat[i][k] == 10000000000000000ll)continue;
				for (int j = 1; j <= N; j++) {
					if (x.mat[k][j] == 10000000000000000ll)continue;
					ret.mat[i][j] = min(ret.mat[i][j], mat[i][k] + x.mat[k][j]);
				}
			}
		return ret;
	}

	void ksm(ll k, Matrixmn base) {
		while (k) {
			if (k & 1)*this = *this * base;
			base = base * base;
			k >>= 1;
		}
	}
};

template<const int N>
class Matrixmx {
public:
	array<array<ll, N + 1>, N + 1> mat;

	Matrixmx() {
		for (int i = 0; i <= N; i++)
			for (int j = 0; j <= N; j++)
				mat[i][j] = 0;
	}

	Matrixmx operator* (const Matrixmx& x) {
		// floyd 求最长路
		Matrixmx ret;
		for (int k = 1; k <= N; k++)
			for (int i = 1; i <= N; i++) {
				if (mat[i][k] == 0)continue;
				for (int j = 1; j <= N; j++) {
					if (x.mat[k][j] == 0)continue;
					ret.mat[i][j] = max(ret.mat[i][j], mat[i][k] + x.mat[k][j]);
				}
			}
		return ret;
	}

	void ksm(ll k, Matrixmx base) {
		while (k) {
			if (k & 1)*this = *this * base;
			base = base * base;
			k >>= 1;
		}
	}
};

Matrixmn<105> mn, mnbase;
Matrixmx<105> mx, mxbase;
void solve(int CASE)
{
	int n, m, q; cin >> n >> m >> q;
	fa(i, 1, m) {
		ll u, v, w; cin >> u >> v >> w;
		mn.mat[u][v] = min(mn.mat[u][v], w);
		mn.mat[v][u] = min(mn.mat[v][u], w);
		mx.mat[u][v] = max(mx.mat[u][v], w);
		mx.mat[v][u] = max(mx.mat[v][u], w);
	}
	mnbase = mn, mxbase = mx; // 原始邻接矩阵

	var ans = vector<pll>(q + 1);
	var input = vector<tuple<ll, int, int, int>>(q + 1);
	fa(i, 1, q) {
		ll u, v, k; cin >> u >> v >> k;
		input[i] = { k, u, v, i };
	}
	sort(all1(input), [](const var& x, const var& y)->bool {
		return get<0>(x) < get<0>(y);
		});

	ll last = 1; // 所有数一起快速幂，总共快速幂 1e9，防止分开快速幂 T 掉 
	fa(i, 1, q) {
		const var& [k, u, v, id] = input[i];
		ll cha = k - last;
		mn.ksm(cha, mnbase);
		mx.ksm(cha, mxbase);
		if (mn.mat[u][v] == 1e16)ans[id] = { -1, -1 };
		else ans[id] = { mn.mat[u][v], mx.mat[u][v] };
		last = k;
	}
	fa(i, 1, q)cout << ans[i].px << ' ' << ans[i].py << endl;
	return;
}
